public static ETGSalesAgreementFixationDP construct()
{
    ETGSalesAgreementFixationDP  dataProvider;

    dataProvider = new ETGSalesAgreementFixationDP();

    return dataProvider;
}

public ETG_SalesAgreementFixationTmp processReport (ETGSalesAgreementFixationContract _contract)
{
    SalesAgreementId        salesAgreementId;
    SalesAgreementHeader    salesAgreementHeader;

    salesAgreementId        =   _contract.parmSalesAgreementId();
    salesAgreementHeader    =   SalesAgreementHeader::findAgreementId(salesAgreementId);

    salesAgreementFixationTmp.SalesAgreementId            =   salesAgreementHeader.SalesNumberSequence;
    salesAgreementFixationTmp.CustAccount                 =   salesAgreementHeader.CustAccount;
    salesAgreementFixationTmp.SalesAgreementHeaderRecId   =   salesAgreementHeader.RecId;

    ttsbegin;
    salesAgreementFixationTmp.insert();
    ttscommit;

    // Select all rows from tmp table and return
    select salesAgreementFixationTmp;
    return salesAgreementFixationTmp;
}
